#!/usr/bin/env python3
"""Apply script: fix 4 known defects before Phase 10 observation window.

Defect 1: EAL confidence bug — included_count always None when canonical_ids_json is empty
Defect 2: use_canonical=False default inverts safety in event_queries helpers
Defect 4: Legacy recaps table — add deprecation marker (minimal approach)
Defect 5: Schema drift gate — add init_and_migrate equivalence test

Defect 3 (phantom root files) was already fixed — no action needed.

Usage (from repo root):
    python scripts/apply_defect_fixes_v1.py

Or:
    cp apply_defect_fixes_v1.py squadvault/scripts/
    cd squadvault && python scripts/apply_defect_fixes_v1.py

Verified against: 978 passed, 2 skipped (baseline was 969 passed, 2 skipped)
"""
import base64
import json
import os
import sys
from pathlib import Path

MANIFEST = json.loads("""{"src/squadvault/recaps/weekly_recap_lifecycle.py": "", "src/squadvault/core/queries/event_queries.py": "", "src/squadvault/core/queries/franchise_queries.py": "", "src/squadvault/core/queries/_run_narrative_event_counts.py": "", "src/squadvault/core/storage/schema.sql": "", "Tests/test_sqlite_store_and_queries_v1.py": "", "Tests/test_defect_fixes_v1.py": "", "Tests/test_schema_init_migrate_equivalence_v1.py": ""}""")

def _find_repo_root() -> Path:
    """Find repo root by checking script location, then CWD."""
    # If script is in scripts/, parent is repo root
    script_dir = Path(__file__).resolve().parent
    if script_dir.name == "scripts" and (script_dir.parent / "src" / "squadvault").is_dir():
        return script_dir.parent
    # Try CWD
    cwd = Path.cwd()
    if (cwd / "src" / "squadvault").is_dir():
        return cwd
    return None

def main():
    repo_root = _find_repo_root()
    if repo_root is None:
        print("ERROR: Cannot find src/squadvault/")
        print("Run from repo root, or place this script in scripts/")
        sys.exit(1)

    print(f"Repo root: {repo_root}")
    print(f"Applying defect fixes (4 defects, 8 files)...")
    print()

    for rel_path, b64_content in MANIFEST.items():
        target = repo_root / rel_path
        target.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64_content)
        target.write_bytes(content)
        print(f"  wrote {rel_path} ({len(content)} bytes)")

    print()
    print("All files written. Run:")
    print("  PYTHONPATH=src python -m pytest Tests/ -q")
    print()
    print("Expected: 978 passed, 2 skipped")

if __name__ == "__main__":
    main()
